@page "/profile"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <h3>Roles</h3>
        <ul>
            @foreach (var claim in context.User.Claims.Where(c => c.Type == System.Security.Claims.ClaimTypes.Role))
            {
                <li>@claim.Value</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not authenticated.</p>
    </NotAuthorized>
</AuthorizeView>

@page "/editor"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@attribute [Authorize(Roles = "Editor")]
@rendermode InteractiveAuto

<PageTitle>Editor</PageTitle>

<h1>Editor Page</h1>

<AuthorizeView Roles="Editor">
    <Authorized>
        <p>Welcome, Editor! You have access to this page.</p>
    </Authorized>
    <NotAuthorized>
        <p>Access denied. You do not have the "Editor" role.</p>
    </NotAuthorized>
</AuthorizeView>

@page "/viewer"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@attribute [Authorize]
@rendermode InteractiveAuto

